const allData = {{workflowparams:allData}};
const unique = `${allData.to_created_by || ""}_${Date.now()}`;

return {
  unique
};

const allData = {{workflowparams:allData}}

const zeroQtyArray = [];
for (const [index, to] of allData.table_to.entries()) {
  if (to.to_qty <= 0) {
    zeroQtyArray.push(`#${index + 1}`);
  }
}
let hasZero = 0
let message = null;
if (zeroQtyArray.length > 0) {
  message = `Line${zeroQtyArray.length > 1 ? "s" : ""} ${zeroQtyArray.join(
    ", ",
  )} ha${
    zeroQtyArray.length > 1 ? "ve" : "s"
  } a zero deliver quantity, which may prevent processing.\nIf you proceed, it will delete the row with 0 deliver quantity. \nWould you like to proceed?`;
  hasZero = 1
}

return {
  message,
  hasZero
};

const allData = {{workflowparams:allData}};
const tableTo = allData.table_to || [];

// Filter rows that need allocation: to_qty > 0 AND no temp_qty_data
const rowsNeedingAllocation = [];

tableTo.forEach((row, index) => {
  const toQty = parseFloat(row.to_qty) || 0;
  const hasTempData = row.temp_qty_data && 
                      row.temp_qty_data !== "[]" && 
                      row.temp_qty_data.trim() !== "";

  // Only allocate if: has quantity AND no existing allocation AND has material_id
  if (toQty > 0 && !hasTempData && row.material_id) {
    rowsNeedingAllocation.push({
      rowIndex: index,
      materialId: row.material_id,
      quantity: toQty,
      uomId: row.to_order_uom_id,
      plantId: allData.plant_id,
      organizationId: allData.organization_id,
      soLineItemId: row.so_line_item_id || null
    });
  }
});

// Initialize allocation tracker for cross-row deduplication
const allocationTracker = {};

return {
  rowsNeedingAllocation,
  allocationTracker,
  plantId: allData.plant_id,
  organizationId: allData.organization_id,
  totalRowsToAllocate: rowsNeedingAllocation.length
};

const allData = {{workflowparams:allData}};
const rowsNeedingAllocation = {{node:code_node_C58lS8pM.data.rowsNeedingAllocation}};

// Collect unique UOM IDs
const uomIds = new Set();
rowsNeedingAllocation.forEach(row => {
  if (row.uomId) uomIds.add(row.uomId);
});

return {
  uomIds: Array.from(uomIds)
};

const rowsNeedingAllocation = {{node:code_node_C58lS8pM.data.rowsNeedingAllocation}};
const currentIndexRaw = {{node:get_cache_node_aVQIWXIv.data}};
const index = currentIndexRaw ? parseInt(currentIndexRaw, 10) : 0;

const currentRow = rowsNeedingAllocation[index];

return {
  currentRow,
  currentIndex: index,
  nextIndex: index + 1
};

// executeAllocation - Updated with pendingReservedData priority (Production first)
// ============================================================================
// INPUTS
// ============================================================================
const currentRow = {{node:code_node_cvOKI9GU.data.currentRow}};
const itemData = {{node:get_node_pxY9Jxts.data.data}};
const isBatchManaged = itemData.item_batch_management === 1;
const pickingSetup = {{node:get_node_MX4rxQLm.data.data}};
const rawTracker = {{node:get_cache_node_j89l1u3S.data}};
let allocationTracker = {};

// 🔧 NEW: Pending reserved data (fetched from search node)
const pendingReservedData = {{node:search_node_ekF4IJPz.data.data}} || [];

if (rawTracker) {
  if (typeof rawTracker === 'string') {
    try {
      allocationTracker = JSON.parse(rawTracker);
    } catch (e) {
      console.log('Failed to parse allocation tracker, using empty object');
      allocationTracker = {};
    }
  } else if (typeof rawTracker === 'object') {
    allocationTracker = rawTracker;
  }
}

// Pre-fetched data
const allUOMs = {{node:search_node_sgKuGfeN.data.data}} || [];
const allBinLocations = {{node:search_node_d34w6rCv.data.data}} || [];

// Get balance data based on batch management
let balances = [];
let batchMasterData = [];

if (isBatchManaged) {
  batchMasterData = {{node:search_node_dg4nIIRM.data.data}} || [];
  balances = {{node:search_node_ojdgySof.data.data}} || [];
} else {
  balances = {{node:search_node_54hizGno.data.data}} || [];
}

// ============================================================================
// HELPER FUNCTIONS
// ============================================================================

// Get default bin for this item and plant
const getDefaultBin = (itemData, plantId) => {
  if (!itemData.table_default_bin?.length) return null;
  const entry = itemData.table_default_bin.find(bin => bin.plant_id === plantId);
  return entry?.bin_location || null;
};

// Get allocations from other rows of the same material (deduplication)
const getCurrentAllocations = (materialId, currentRowIndex, tracker) => {
  const materialAllocations = tracker[materialId] || {};
  const allocatedQuantities = {};

  Object.entries(materialAllocations).forEach(([rIdx, rowAllocs]) => {
    if (parseInt(rIdx) !== currentRowIndex) {
      Object.entries(rowAllocs).forEach(([locationKey, qty]) => {
        allocatedQuantities[locationKey] = (allocatedQuantities[locationKey] || 0) + qty;
      });
    }
  });

  return allocatedQuantities;
};

// Apply cross-row deduplication to balances
const applyAllocationsToBalances = (balances, allocatedQuantities, isBatchManaged) => {
  return balances.map(balance => {
    const key = isBatchManaged
      ? `${balance.location_id}-${balance.batch_id || "no_batch"}`
      : `${balance.location_id}`;

    const allocatedFromOthers = allocatedQuantities[key] || 0;
    const originalQty = balance.unrestricted_qty || 0;
    const adjustedQty = Math.max(0, originalQty - allocatedFromOthers);

    return {
      ...balance,
      unrestricted_qty: adjustedQty,
      original_unrestricted_qty: originalQty
    };
  });
};

// Find batch master data by batch_id
const findBatchData = (batchId) => {
  if (!isBatchManaged || !batchMasterData.length) return null;
  return batchMasterData.find(b => b.id === batchId) || null;
};

// Lookup bin location from pre-fetched data
const getBinLocationDetails = (locationId) => {
  const binLocation = allBinLocations.find(bin => bin.id === locationId);
  return binLocation ? binLocation.bin_location_combine : locationId;
};

// Lookup UOM name from pre-fetched data
const getUOMName = (uomId) => {
  const uom = allUOMs.find(u => u.id === uomId);
  return uom ? uom.uom_name : "";
};

// ============================================================================
// DEDUPLICATION
// ============================================================================
const allocatedFromOtherRows = getCurrentAllocations(
  currentRow.materialId,
  currentRow.rowIndex,
  allocationTracker
);

const adjustedBalances = applyAllocationsToBalances(
  balances,
  allocatedFromOtherRows,
  isBatchManaged
);

// ============================================================================
// ALLOCATION ENGINE - STEP 0: PRIORITIZE PENDING RESERVED DATA
// ============================================================================
let allAllocations = [];
let remainingQty = currentRow.quantity;

// 🔧 NEW: Sort pending reserved data to prioritize Production over Sales Order
if (pendingReservedData.length > 0 && currentRow.soLineItemId) {
  const sortedReservedData = [...pendingReservedData].sort((a, b) => {
    if (a.doc_type === "Production" && b.doc_type !== "Production") return -1;
    if (a.doc_type !== "Production" && b.doc_type === "Production") return 1;
    return 0;
  });

  for (const reservation of sortedReservedData) {
    if (remainingQty <= 0) break;

    const reservedQty = parseFloat(reservation.open_qty || 0);
    if (reservedQty <= 0) continue;

    // Find matching balance by bin_location and batch_id (if batch-managed)
    const matchingBalance = adjustedBalances.find((b) => {
      const binMatch = b.location_id === reservation.bin_location;
      if (isBatchManaged) {
        return binMatch && b.batch_id === reservation.batch_id;
      }
      return binMatch;
    });

    if (matchingBalance) {
      const availableQty = matchingBalance.unrestricted_qty || 0;
      // Allocate min of: remaining qty, reserved qty, available balance
      const allocatedQty = Math.min(remainingQty, reservedQty, availableQty);

      if (allocatedQty > 0) {
        const binLocationName = getBinLocationDetails(matchingBalance.location_id);
        const batchData = isBatchManaged ? findBatchData(matchingBalance.batch_id) : null;

        // Check if already allocated to this location
        const existingAllocIndex = allAllocations.findIndex((a) => {
          const locMatch = a.balance.location_id === matchingBalance.location_id;
          if (isBatchManaged) {
            return locMatch && a.batchData?.id === matchingBalance.batch_id;
          }
          return locMatch;
        });

        if (existingAllocIndex >= 0) {
          allAllocations[existingAllocIndex].quantity += allocatedQty;
        } else {
          allAllocations.push({
            balance: matchingBalance,
            quantity: allocatedQty,
            binLocation: binLocationName,
            batchData: batchData,
            source: `Reserved (${reservation.doc_type})`  // For debugging
          });
        }

        remainingQty -= allocatedQty;
        // Reduce balance for next iteration
        matchingBalance.unrestricted_qty = Math.max(0, matchingBalance.unrestricted_qty - allocatedQty);
      }
    }
  }
}

// ============================================================================
// ALLOCATION ENGINE - STEP 1: APPLY STRATEGY FOR REMAINING QTY
// ============================================================================
if (remainingQty > 0) {
  const defaultBin = getDefaultBin(itemData, currentRow.plantId);
  const defaultStrategy = pickingSetup.default_strategy_id;
  const fallbackStrategy = pickingSetup.fallback_strategy_id;

  // Helper: Sort by FIFO (expired date)
  const sortByFIFO = (balanceArray) => {
    if (!isBatchManaged) return balanceArray;

    return balanceArray.sort((a, b) => {
      const batchA = findBatchData(a.batch_id);
      const batchB = findBatchData(b.batch_id);

      if (batchA?.expired_date && batchB?.expired_date) {
        return new Date(batchA.expired_date) - new Date(batchB.expired_date);
      }

      return (batchA?.batch_number || "").localeCompare(batchB?.batch_number || "");
    });
  };

  // Helper: Allocate from a list of balances
  const allocateFromBalances = (balanceList) => {
    const allocated = [];

    for (const balance of balanceList) {
      if (remainingQty <= 0) break;

      const availableQty = balance.unrestricted_qty || 0;
      if (availableQty <= 0) continue;

      const allocatedQty = Math.min(remainingQty, availableQty);

      const binLocationName = getBinLocationDetails(balance.location_id);
      const batchData = isBatchManaged ? findBatchData(balance.batch_id) : null;

      allocated.push({
        balance: balance,
        quantity: allocatedQty,
        binLocation: binLocationName,
        batchData: batchData,
        source: "Strategy"  // For debugging
      });

      remainingQty -= allocatedQty;
    }

    return allocated;
  };

  // Get already allocated location keys to exclude
  const allocatedKeys = new Set(
    allAllocations.map((a) =>
      isBatchManaged
        ? `${a.balance.location_id}-${a.batchData?.id || "no_batch"}`
        : `${a.balance.location_id}`
    )
  );

  // Filter out already allocated balances
  const remainingBalances = adjustedBalances.filter((b) => {
    const key = isBatchManaged
      ? `${b.location_id}-${b.batch_id || "no_batch"}`
      : `${b.location_id}`;
    return !allocatedKeys.has(key) && (b.unrestricted_qty || 0) > 0;
  });

  // STRATEGY: FIXED BIN
  if (defaultStrategy === "FIXED BIN") {
    // Step 1: Try default bin first (only if configured)
    if (defaultBin) {
      const defaultBinBalances = remainingBalances.filter(
        b => b.location_id === defaultBin
      );

      const sortedDefaultBalances = sortByFIFO(defaultBinBalances);
      const defaultAllocations = allocateFromBalances(sortedDefaultBalances);
      allAllocations.push(...defaultAllocations);
    }

    // Step 2: Fallback to RANDOM for remainder (or if no default bin configured)
    if (remainingQty > 0 && fallbackStrategy === "RANDOM") {
      const otherBalances = remainingBalances.filter(
        b => !defaultBin || b.location_id !== defaultBin
      );

      const sortedOtherBalances = sortByFIFO(otherBalances);
      const fallbackAllocations = allocateFromBalances(sortedOtherBalances);
      allAllocations.push(...fallbackAllocations);
    }
  }
  // STRATEGY: RANDOM
  else if (defaultStrategy === "RANDOM") {
    const sortedBalances = sortByFIFO(remainingBalances);
    const randomAllocations = allocateFromBalances(sortedBalances);
    allAllocations.push(...randomAllocations);
  }
}

// ============================================================================
// BUILD RESULTS
// ============================================================================

// Build temp_qty_data array
const tempQtyData = allAllocations.map(alloc => ({
  material_id: currentRow.materialId,
  location_id: alloc.balance.location_id,
  block_qty: alloc.balance.block_qty,
  reserved_qty: alloc.balance.reserved_qty,
  unrestricted_qty: alloc.balance.original_unrestricted_qty || alloc.balance.unrestricted_qty,
  qualityinsp_qty: alloc.balance.qualityinsp_qty,
  intransit_qty: alloc.balance.intransit_qty,
  balance_quantity: alloc.balance.balance_quantity,
  plant_id: currentRow.plantId,
  organization_id: alloc.balance.organization_id,
  is_deleted: 0,
  to_quantity: alloc.quantity,
  ...(alloc.batchData && { batch_id: alloc.batchData.id })
}));

// Get UOM name from pre-fetched data
const uomName = getUOMName(currentRow.uomId);

// Build view_stock summary
const summaryLines = allAllocations.map((alloc, idx) => {
  let line = `${idx + 1}. ${alloc.binLocation}: ${alloc.quantity} ${uomName}`;
  if (alloc.batchData) {
    line += `\n[${alloc.batchData.batch_number}]`;
  }
  return line;
});

const totalAllocated = allAllocations.reduce((sum, alloc) => sum + alloc.quantity, 0);
const viewStock = totalAllocated > 0
  ? `Total: ${totalAllocated} ${uomName}\n\nDETAILS:\n${summaryLines.join("\n")}`
  : "";

// Update allocation tracker
const updatedTracker = { ...allocationTracker };
if (!updatedTracker[currentRow.materialId]) {
  updatedTracker[currentRow.materialId] = {};
}

const rowAllocations = {};
allAllocations.forEach(alloc => {
  const key = alloc.batchData
    ? `${alloc.balance.location_id}-${alloc.batchData.id}`
    : `${alloc.balance.location_id}`;
  rowAllocations[key] = alloc.quantity;
});

updatedTracker[currentRow.materialId][currentRow.rowIndex] = rowAllocations;

// ============================================================================
// RETURN RESULTS
// ============================================================================
return {
  temp_qty_data: JSON.stringify(tempQtyData),
  view_stock: viewStock,
  total_allocated: totalAllocated,
  rowIndex: currentRow.rowIndex,
  updatedTracker: updatedTracker
};

const rawtableTO = {{node:get_cache_node_XGpEIHGk.data}};
let tableTO = [];

if (rawtableTO) {
  if (typeof rawtableTO === 'string') {
    tableTO = JSON.parse(rawtableTO);
  } else {
    tableTO = rawtableTO;
  }
}

const allocationResult = {{node:code_node_KTHlcvbv.data}};
const rowIndex = allocationResult.rowIndex;

// Update specific row
if (tableTO[rowIndex]) {
  tableTO[rowIndex].temp_qty_data = allocationResult.temp_qty_data;
  tableTO[rowIndex].view_stock = allocationResult.view_stock;

  const toQty = parseFloat(tableTO[rowIndex].to_qty) || 0;
  const initialDeliveredQty = parseFloat(tableTO[rowIndex].to_initial_delivered_qty) || 0;
  const orderedQty = parseFloat(tableTO[rowIndex].to_order_quantity) || 0;

  tableTO[rowIndex].to_delivered_qty = initialDeliveredQty + toQty;
  tableTO[rowIndex].to_undelivered_qty = orderedQty - (initialDeliveredQty + toQty);
}

return {
  tableTO: tableTO,
  updatedTracker: allocationResult.updatedTracker
};

const allData = {{workflowparams:allData}};
const totalRowsToAllocate = {{node:code_node_C58lS8pM.data.totalRowsToAllocate}};

// If no rows were allocated, just return original table_to
if (totalRowsToAllocate === 0) {
  return { tableTO: allData.table_to };
}

// Otherwise, get the allocated table from Redis
const rawTableTo = {{node:get_cache_node_CBiQBoVP.data}};

let tableTO = [];
if (typeof rawTableTo === 'string') {
  tableTO = JSON.parse(rawTableTo);
} else {
  tableTO = rawTableTo || allData.table_to;
}

return { tableTO };

let allData = {{workflowparams:allData}};
const updatedTO = [];
const saveAs = {{workflowparams:saveAs}};
const pickingSetup = {{node:get_node_MX4rxQLm.data.data}};
const pageStatus = {{workflowparams:pageStatus}}
const isForceComplete = {{workflowparams:isForceComplete}} || 0;

const skippedRows = [];

if (pickingSetup?.picking_mode === "Auto" && saveAs !== "Cancelled") {
  const tableTO = {{node:code_node_fsjJarKT.data.tableTO}}
  if (tableTO?.length > 0) {
    allData.table_to = tableTO
  }
}

for (const [index, toLineItem] of allData.table_to.entries()) {
  if (!toLineItem.to_qty || parseFloat(toLineItem.to_qty) === 0) {
    continue;
  }

  const tempQtyData = toLineItem.temp_qty_data;
  const isEmpty =
    !tempQtyData ||
    tempQtyData === "" ||
    tempQtyData === "[]" ||
    tempQtyData === null;

  if (isEmpty) {
    skippedRows.push({
      index: index,
      material_name: toLineItem.material_name || "Unknown",
      to_qty: toLineItem.to_qty,
      so_no: toLineItem.so_no || "",
      reason: "temp_qty_data is empty",
    });
    continue;
  }

  try {
    const parsedTempQty = JSON.parse(tempQtyData);
    const totalAllocated = parsedTempQty.reduce(
      (sum, item) => sum + (parseFloat(item.to_quantity) || 0),
      0
    );
    const toQty = parseFloat(toLineItem.to_qty) || 0;

    if (Math.abs(totalAllocated - toQty) > 0.001) {
      skippedRows.push({
        index: index,
        material_name: toLineItem.material_name || "Unknown",
        to_qty: toLineItem.to_qty,
        allocated_qty: totalAllocated,
        so_no: toLineItem.so_no || "",
        reason: `temp_qty_data total (${totalAllocated}) != to_qty (${toQty})`,
      });
      continue;
    }
  } catch (e) {
    skippedRows.push({
      index: index,
      material_name: toLineItem.material_name || "Unknown",
      to_qty: toLineItem.to_qty,
      so_no: toLineItem.so_no || "",
      reason: "temp_qty_data parse error",
    });
    continue;
  }

  toLineItem.customer_id = allData.customer_name || null;
  toLineItem.organization_id = allData.organization_id;
  toLineItem.plant_id = allData.plant_id || null;
  toLineItem.billing_state_id = allData.billing_address_state || null;
  toLineItem.billing_country_id = allData.billing_address_country || null;
  toLineItem.shipping_state_id = allData.shipping_address_state || null;
  toLineItem.shipping_country_id = allData.shipping_address_country || null;
  toLineItem.assigned_to = allData.assigned_to || null;
  toLineItem.line_index = index + 1;

  if (saveAs === "Cancelled") {
    toLineItem.picking_status = toLineItem.picking_status ? "Cancelled" : null;
  }

  if (
    pickingSetup &&
    (!allData.picking_status || allData.picking_status === "") &&
    saveAs === "Created" &&
    pickingSetup.picking_required === 1
  ) {
    if (pickingSetup.auto_trigger_to === 1) {
      toLineItem.picking_status = "Created";
    } else {
      toLineItem.picking_status = "Not Created";
    }
  }

  if (isForceComplete === 1) {
    toLineItem.temp_qty_data = toLineItem.picked_temp_qty_data;
    toLineItem.view_stock = toLineItem.picked_view_stock;
    toLineItem.to_qty = toLineItem.picked_qty;
  }

  updatedTO.push(toLineItem);
}

allData.table_to = updatedTO;

if ({{workflowparams:pageStatus}} === "Add") {
  allData.to_status = "Draft";
}

if (
  pickingSetup &&
  (!allData.picking_status || allData.picking_status === "") &&
  saveAs === "Created" &&
  pickingSetup.picking_required === 1
) {
  if (pickingSetup.auto_trigger_to === 1) {
    allData.picking_status = "Created";
  } else {
    allData.picking_status = "Not Created";
  }
}

if (saveAs !== "Cancelled") {
  if (saveAs === "Draft") {
    if (
      allData.to_no_type !== -9999 &&
      (!allData.to_no ||
        allData.to_no === null ||
        allData.to_no === "")
    ) {
      allData.to_no = "draft";
    }
  } else {
    if (
      allData.to_no_type !== -9999 &&
      (!allData.to_no ||
        allData.to_no === null ||
        allData.to_no === "" ||
        allData.to_status === "Draft")
    ) {
      allData.to_no = "issued";
    }
  }
}

if (saveAs === "Cancelled") {
  allData.picking_status = allData.picking_status ? "Cancelled" : null;
  allData.to_no = allData.to_no + "-Cancelled";
}

let needSOCleanUp = 0

if (allData.to_status === "Created") {
  const originalTO = {{node:get_node_zG6KDDEF.data.data}};

  allData.table_to.forEach((item) => {
    const originalItem = originalTO.table_to?.find(
      orig => orig.so_line_item_id === item.so_line_item_id
    );
    if (originalItem) {
      item.prev_temp_qty_data = originalItem.temp_qty_data;
    }
  });

  if (allData.table_to.length !== originalTO.table_to.length) {
    needSOCleanUp = 1
  }
}

let invalidData = 0;
let invalidDataMessage = "";

if (skippedRows.length > 0) {
  invalidData = 1;

  const rowDetails = skippedRows.map(row => 
    `Row ${row.index + 1}: ${row.material_name} - qty: ${row.to_qty}${row.allocated_qty !== undefined ? `, allocated: ${row.allocated_qty}` : ""}${row.so_no ? ` [SO: ${row.so_no}]` : ""} — ${row.reason}`
  ).join("\n");

  invalidDataMessage = `Warning: ${skippedRows.length} row(s) skipped due to invalid allocation data:\n\n${rowDetails}\n\nThese rows may need manual allocation or the allocation workflow may have failed.`;
}

return {
  allData: allData,
  to_status: allData.to_status,
  picking_status: allData.picking_status === "" ? null : allData.picking_status,
  packing_status: allData.packing_status,
  needSOCleanUp: needSOCleanUp,
  invalidData: invalidData,
  invalidDataMessage: invalidDataMessage,
  isForceComplete: isForceComplete || 0,
};

return {
  required_fields: JSON.stringify([
    { name: "customer_name", label: "Customer" },
    { name: "plant_id", label: "Plant" },
    { name: "so_id", label: "Sales Order" },
    { name: "to_no", label: "Transfer Order Number" },
    {
        name: "table_to",
        label: "Item Table",
        isArray: true,
        arrayType: "object",
        arrayFields: [],
    },
]),
  data: JSON.stringify({
    customer_name: {{node:code_node_Nj60Z2XF.data.allData.customer_name}},
    plant_id: {{node:code_node_Nj60Z2XF.data.allData.plant_id}},
    so_id: {{node:code_node_Nj60Z2XF.data.allData.so_id}},
    to_no: {{node:code_node_Nj60Z2XF.data.allData.to_no}},
    table_to: {{node:code_node_Nj60Z2XF.data.allData.table_to}}
  })
}

const pickingSetup = {{node:get_node_MX4rxQLm.data.data}} || {};
const saveAs = {{workflowparams:saveAs}}
const pageStatus = {{workflowparams:pageStatus}}
let picking_status = {{node:code_node_Nj60Z2XF.data.picking_status}}

if (pickingSetup && (!picking_status || picking_status === "") && saveAs === "Created" && pickingSetup.picking_required === 1) {
  if (pickingSetup.auto_trigger_to === 1) {
    picking_status = "Created"
  } else {
    picking_status = "Not Created"
  }
}

if (pickingSetup && pickingSetup.picking_required === 1 && saveAs === "Cancelled") {
  picking_status = "Cancelled"
}

return {
  picking_status: picking_status,
  auto_trigger_to: pickingSetup.auto_trigger_to
}

const allData = {{node:code_node_Nj60Z2XF.data.allData}}
const tableTO = allData.table_to;

return {
  tableTO: tableTO
